import{_ as t,o as i,c as o,ag as s}from"./chunks/framework.ePeAWSvT.js";const a="/assets/session-values-action-tree.CC0WkEtE.png",n="/assets/session-values-add-action.Bxrk4HEm.png",r="/assets/session-values-form.XWfI15xx.png",d="/assets/session-values-form-multiple-lists.CZPEiXHy.png",y=JSON.parse('{"title":"Session Values","description":"","frontmatter":{},"headers":[],"relativePath":"guide/session-values.md","filePath":"guide/session-values.md"}'),l={name:"guide/session-values.md"};function c(h,e,p,u,g,m){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="session-values" tabindex="-1">Session Values <a class="header-anchor" href="#session-values" aria-label="Permalink to &quot;Session Values&quot;">​</a></h1><p>Session Values allow you to extract data from a connector&#39;s API response during one action and reuse it in subsequent actions within the same endpoint. This is essential for APIs that require multi-step workflows where later requests depend on identifiers or tokens returned by earlier ones.</p><p>A common example is the <strong>Shopify Order Edit API</strong>, where you must first begin an edit session to obtain a <code>calculatedOrder</code> ID, then reference that ID when committing line item changes.</p><h2 id="when-to-use-session-values" tabindex="-1">When to Use Session Values <a class="header-anchor" href="#when-to-use-session-values" aria-label="Permalink to &quot;When to Use Session Values&quot;">​</a></h2><p>Use a <strong>Get Session Values</strong> action when your integration needs to:</p><ul><li>Extract an identifier from an API response and pass it to a later save action (e.g. Shopify&#39;s <code>calculatedOrder.id</code>)</li><li>Map response list items to child entities by matching on a shared property (e.g. matching Shopify line items to Order Lines by SKU)</li><li>Chain API calls where the second call requires data returned by the first</li></ul><h2 id="overview-shopify-order-line-edits" tabindex="-1">Overview: Shopify Order Line Edits <a class="header-anchor" href="#overview-shopify-order-line-edits" aria-label="Permalink to &quot;Overview: Shopify Order Line Edits&quot;">​</a></h2><p>Shopify&#39;s <a href="https://shopify.dev/docs/api/admin-rest/2025-01/resources/orderedit" target="_blank" rel="noreferrer">Order Edit API</a> follows a begin/commit pattern:</p><ol><li><strong>Begin Edit</strong> — <code>POST /orders/{id}/edits/begin.json</code> returns an <code>orderEdit</code> object containing a <code>calculatedOrder</code> with an <code>id</code> and its <code>lineItems</code></li><li><strong>Modify Lines</strong> — Use the <code>calculatedOrder.id</code> to add, remove, or update line items</li><li><strong>Commit Edit</strong> — <code>POST /orders/{id}/edits/{calculatedOrderId}/commit.json</code> finalizes the changes</li></ol><p>Session Values bridge step 1 and step 3 by extracting the <code>calculatedOrder.id</code> from the begin response and making it available as a mappable property in the commit action.</p><h2 id="adding-a-get-session-values-action" tabindex="-1">Adding a Get Session Values Action <a class="header-anchor" href="#adding-a-get-session-values-action" aria-label="Permalink to &quot;Adding a Get Session Values Action&quot;">​</a></h2><p>Within an endpoint&#39;s <strong>Data Source</strong> tab, select <strong>On Save</strong> from the sidebar to view the save action tree.</p><p><img src="'+a+'" alt="Action tree with Get Session Values"></p><p>To add a new Get Session Values action:</p><ol><li>Click the <strong>...</strong> menu on the parent save action card</li><li>Select <strong>Add Action</strong></li><li>Choose <strong>Get Session Values Action</strong> from the list</li></ol><p><img src="'+n+'" alt="Add Inner Action modal"></p><h2 id="configuring-extractions" tabindex="-1">Configuring Extractions <a class="header-anchor" href="#configuring-extractions" aria-label="Permalink to &quot;Configuring Extractions&quot;">​</a></h2><p>Click the <strong>...</strong> menu on a Get Session Values action card and select <strong>Edit</strong> to open the configuration form.</p><p><img src="'+r+'" alt="Get Session Values form"></p><p>Each Get Session Values action contains one or more <strong>extractions</strong>. An extraction defines how to pull a value from the connector&#39;s API response and make it available to subsequent actions.</p><h3 id="basic-extraction-header-level-value" tabindex="-1">Basic Extraction (Header-Level Value) <a class="header-anchor" href="#basic-extraction-header-level-value" aria-label="Permalink to &quot;Basic Extraction (Header-Level Value)&quot;">​</a></h3><p>Use a basic extraction to capture a single value from the API response, such as the <code>calculatedOrder.id</code>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Model Property</strong></td><td>The name this value will be known by in property mappings</td><td><code>CalculatedOrderId</code></td></tr><tr><td><strong>Connector Property</strong></td><td>The JSON path in the API response to extract from</td><td><code>calculatedOrder.id</code></td></tr></tbody></table><p>Once configured, <code>CalculatedOrderId</code> becomes available as a <strong>Session Value</strong> in the property picker for all subsequent actions. You can use it in save URLs (e.g. <code>/orders/{OrderNumber}/edits/{CalculatedOrderId}/commit.json</code>) or in property mappings.</p><h3 id="collection-extraction-map-to-children" tabindex="-1">Collection Extraction (Map to Children) <a class="header-anchor" href="#collection-extraction-map-to-children" aria-label="Permalink to &quot;Collection Extraction (Map to Children)&quot;">​</a></h3><p>Enable the <strong>Map to Children</strong> toggle when the API response contains a list that needs to be matched to child entities. For example, mapping Shopify&#39;s <code>calculatedOrder.lineItems</code> to your Order Lines:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Model Property</strong></td><td>The child property to populate</td><td><code>LineItemId</code></td></tr><tr><td><strong>Connector Property</strong></td><td>The JSON path for the value to extract from each list item</td><td><code>calculatedOrder.lineItems.id</code></td></tr><tr><td><strong>Target List</strong></td><td>The child entity list to map into</td><td><code>OrderLines</code></td></tr><tr><td><strong>Model Match Property</strong></td><td>The child entity property to match on</td><td><code>SKU</code></td></tr><tr><td><strong>Connector List Property</strong></td><td>The JSON path to the list in the response</td><td><code>calculatedOrder.lineItems</code></td></tr><tr><td><strong>Connector Match Property</strong></td><td>The list item property to match against the model</td><td><code>sku</code></td></tr></tbody></table><p>This tells the engine: <em>&quot;For each item in <code>calculatedOrder.lineItems</code>, find the Order Line whose <code>SKU</code> matches the item&#39;s <code>sku</code>, and set that Order Line&#39;s <code>LineItemId</code> to the item&#39;s <code>id</code>.&quot;</em></p><h3 id="multiple-lists-extraction" tabindex="-1">Multiple Lists Extraction <a class="header-anchor" href="#multiple-lists-extraction" aria-label="Permalink to &quot;Multiple Lists Extraction&quot;">​</a></h3><p>Some APIs return two or more parallel lists in the same response with no cross-reference between them. For example, Shopify&#39;s <code>orderEditBegin</code> mutation returns both <code>originalOrder.lineItems.edges</code> and <code>calculatedOrder.lineItems.edges</code> — the calculated list has the IDs you need, but contains no pointer back to the original line items.</p><p>Enable the <strong>Use Multiple Lists</strong> toggle to correlate items from separate lists by their position (index). Each list is given a user-chosen <strong>prefix</strong> that becomes a namespace in the connector property paths.</p><p><img src="'+d+`" alt="Multiple Lists extraction form"></p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Model Property</strong></td><td>The child property to populate</td><td><code>CalculatedLineItemId</code></td></tr><tr><td><strong>Connector Property</strong></td><td>Path to the value to extract, prefixed by list name</td><td><code>calculated.node.id</code></td></tr><tr><td><strong>Target List</strong></td><td>The child entity list to map into</td><td><code>LineItems</code></td></tr><tr><td><strong>Model Match Property</strong></td><td>The child entity property to match on</td><td><code>Id</code> (PrimaryKey)</td></tr><tr><td><strong>Connector Match Property</strong></td><td>Path to the match value, prefixed by list name</td><td><code>original.node.id</code></td></tr><tr><td><strong>Connector Lists</strong></td><td>A set of prefix → list path pairs</td><td>See below</td></tr></tbody></table><h4 id="connector-lists-configuration" tabindex="-1">Connector Lists Configuration <a class="header-anchor" href="#connector-lists-configuration" aria-label="Permalink to &quot;Connector Lists Configuration&quot;">​</a></h4><p>Each row in the Connector Lists editor maps a prefix name to a JSON path:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Path</th></tr></thead><tbody><tr><td><code>original</code></td><td><code>data.orderEditBegin.calculatedOrder.originalOrder.lineItems.edges[*]</code></td></tr><tr><td><code>calculated</code></td><td><code>data.orderEditBegin.calculatedOrder.lineItems.edges[*]</code></td></tr></tbody></table><p>At runtime the engine resolves both lists, zips them by index, and constructs a composite object per position:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;original&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;node&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gid://shopify/LineItem/15810547548386&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;calculated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;node&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gid://shopify/CalculatedLineItem/15810547548386&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The <strong>Connector Match Property</strong> (<code>original.node.id</code>) is evaluated against this composite to find the matching child entity, and the <strong>Connector Property</strong> (<code>calculated.node.id</code>) extracts the value to store as a session value on that entity. Downstream actions can then reference <code>{SESSION:CalculatedLineItemId}</code> in URL templates or property mappings.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>All lists in a multiple-list extraction must have the same number of items. If the lengths differ, the extraction is skipped and a warning is logged.</p></div><h2 id="execution-order" tabindex="-1">Execution Order <a class="header-anchor" href="#execution-order" aria-label="Permalink to &quot;Execution Order&quot;">​</a></h2><p>Session Values respect the action execution order within the action tree:</p><ol><li><strong>Pre-child actions</strong> run first (in array order) — this is where Get Session Values should typically be placed</li><li><strong>Child config saves</strong> run next</li><li><strong>Post-child actions</strong> run last (actions with &quot;After Child Configs?&quot; enabled)</li></ol><p>A Get Session Values action can only reference values from actions that execute <strong>before</strong> it. The visual action tree shows a <strong>Child Saves</strong> separator when post-child actions are present, making the execution boundary clear.</p><h3 id="after-child-configs" tabindex="-1">After Child Configs? <a class="header-anchor" href="#after-child-configs" aria-label="Permalink to &quot;After Child Configs?&quot;">​</a></h3><p>Enable the <strong>After Child Configs?</strong> toggle on a Get Session Values action if you need to extract values from an API call that runs after child entities have been saved. This is uncommon but useful when a parent API call depends on child data being committed first.</p><h2 id="using-session-values-in-property-mappings" tabindex="-1">Using Session Values in Property Mappings <a class="header-anchor" href="#using-session-values-in-property-mappings" aria-label="Permalink to &quot;Using Session Values in Property Mappings&quot;">​</a></h2><p>Once a Get Session Values action is configured, the extracted values appear automatically in the <strong>Central Property</strong> picker under a <strong>Session Values</strong> group. This means you can select them just like any other schema property when building request or response mappings.</p><p>Session values are scoped to the schema they target:</p><ul><li><strong>Header-level extractions</strong> (no &quot;Map to Children&quot;) appear in the parent entity&#39;s property picker</li><li><strong>Collection extractions</strong> (with &quot;Map to Children&quot;) appear in the child entity&#39;s property picker, scoped to the target list&#39;s schema</li></ul><h2 id="example-complete-shopify-order-edit-flow" tabindex="-1">Example: Complete Shopify Order Edit Flow <a class="header-anchor" href="#example-complete-shopify-order-edit-flow" aria-label="Permalink to &quot;Example: Complete Shopify Order Edit Flow&quot;">​</a></h2><p>Here is how the full save action tree looks for a Shopify order line edit integration:</p><table tabindex="0"><thead><tr><th>Action</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Begin Order Edit</strong></td><td>EndpointSave (root)</td><td>Calls <code>POST /orders/{id}/edits/begin.json</code></td></tr><tr><td>  → <strong>Extract Edit Session</strong></td><td>GetSessionValues</td><td>Extracts <code>CalculatedOrderId</code> and maps <code>LineItemId</code> to Order Lines</td></tr><tr><td>  — <em>Child Saves</em> —</td><td></td><td>Child endpoints save their line item changes</td></tr><tr><td>  → <strong>Save Line Changes</strong></td><td>EndpointSave (after children)</td><td>Calls <code>POST /orders/{id}/edits/{CalculatedOrderId}/commit.json</code></td></tr></tbody></table><p>The key insight is that <code>CalculatedOrderId</code> is extracted once by the Get Session Values action, then referenced by the commit action&#39;s URL template — without needing to hard-code or manually pass the value between steps.</p><h3 id="using-multiple-lists-for-disconnected-responses" tabindex="-1">Using Multiple Lists for Disconnected Responses <a class="header-anchor" href="#using-multiple-lists-for-disconnected-responses" aria-label="Permalink to &quot;Using Multiple Lists for Disconnected Responses&quot;">​</a></h3><p>When the API response contains disconnected parallel lists (like Shopify&#39;s GraphQL <code>orderEditBegin</code> mutation which returns both <code>originalOrder.lineItems</code> and <code>calculatedOrder.lineItems</code> with no cross-reference), the <strong>Extract Edit Session</strong> action uses a multiple-lists extraction:</p><table tabindex="0"><thead><tr><th>Extraction</th><th>Type</th><th>Config</th></tr></thead><tbody><tr><td><code>CalculatedOrderId</code></td><td>Scalar</td><td>Connector Property: <code>data.orderEditBegin.calculatedOrder.id</code></td></tr><tr><td><code>CalculatedLineItemId</code></td><td>Multiple Lists</td><td>Match on <code>original.node.id</code> → extract <code>calculated.node.id</code></td></tr></tbody></table><p>The multiple-lists extraction correlates the original and calculated line item arrays by position, matches each original line item to the corresponding child entity, and stores the calculated line item ID as a session value — which is then available as <code>{SESSION:CalculatedLineItemId}</code> in the <code>orderEditSetQuantity</code> mutation.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint action inputs and parameterization</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions to Common Model properties</li><li><a href="./datahub-data-adaptation.html">Data Adaptation</a> — Transform data during reads and writes</li><li><a href="./datahub-relationships.html">Endpoint Relationships</a> — Configure child endpoints and dependent publishers</li></ul>`,60)])])}const b=t(l,[["render",c]]);export{y as __pageData,b as default};
